#!/usr/bin/env node

import { mkdir, readFile, readdir, rm, writeFile } from "node:fs/promises";
import path from "node:path";

const rootDir = process.cwd();
const repoName = path.basename(rootDir);
const generatedNotice =
  "<!-- Generated by `pnpm ai:sync`. Do not edit directly; update the canonical files in `ai/` instead. -->";
const geminiExtensionName = `${repoName}-skills`;
const generatedCursorRuleNames = new Set([
  "01-repo.mdc",
  "20-frontend.mdc",
  "30-backend.mdc",
  "40-docs.mdc",
]);

async function main() {
  const skillIndexPath = path.join(rootDir, "ai/skills/_index.md");
  const skillIndex = await readFile(skillIndexPath, "utf8");
  const skills = parseSkillIndex(skillIndex);

  if (skills.length === 0) {
    throw new Error("No skills found in ai/skills/_index.md");
  }

  await removeStaleGeneratedFiles(skills);
  await writeAdapterReadmes(skills);
  await writeGeminiExtensionFiles(skills);

  for (const skill of skills) {
    const sourcePath = path.join(rootDir, skill.sourcePath);
    const sourceBody = await readFile(sourcePath, "utf8");
    const skillBody = buildSkillBody(skill, sourceBody);

    await writeClaudeSkill(skill, skillBody);
    await writeGeminiCommand(skill);
    await writeGeminiExtensionSkill(skill, skillBody);
    await writeCodexSkill(skill, skillBody);
  }

  await writeCodexIndex(skills);
  await writeCopilotInstructions();
  await writeCursorRules();

  process.stdout.write(
    [
      "Synced AI context adapters:",
      `- Claude skills: ${skills.length}`,
      `- Gemini commands: ${skills.length}`,
      `- Gemini extension skills: ${skills.length}`,
      `- Codex skills: ${skills.length}`,
      `- Cursor rules: ${generatedCursorRuleNames.size}`,
      "- GitHub Copilot instructions: 1",
    ].join("\n"),
  );
}

function parseSkillIndex(markdown) {
  const skills = [];
  let current = null;

  for (const line of markdown.split("\n")) {
    const headingMatch = line.match(/^### `([^`]+)`$/);
    if (headingMatch) {
      if (current) {
        skills.push(finalizeSkill(current));
      }

      current = {
        name: headingMatch[1],
      };
      continue;
    }

    if (!current) {
      continue;
    }

    const sourceMatch = line.match(/^- 위치: `([^`]+)`$/);
    if (sourceMatch) {
      current.sourcePath = sourceMatch[1];
      continue;
    }

    const usageMatch = line.match(/^- 사용 시점: (.+)$/);
    if (usageMatch) {
      current.useWhen = usageMatch[1].trim();
    }
  }

  if (current) {
    skills.push(finalizeSkill(current));
  }

  return skills;
}

function finalizeSkill(skill) {
  if (!skill.sourcePath || !skill.useWhen) {
    throw new Error(
      `Incomplete skill entry for "${skill.name}" in ai/skills/_index.md`,
    );
  }

  return skill;
}

function buildSkillBody(skill, sourceBody) {
  if (hasFrontmatter(sourceBody)) {
    return `${sourceBody.trim()}\n`;
  }

  const description = `Use when ${skill.useWhen}`;

  return [
    "---",
    `name: ${skill.name}`,
    `description: ${yamlQuote(description)}`,
    "---",
    "",
    sourceBody.trim(),
    "",
  ].join("\n");
}

function hasFrontmatter(markdown) {
  return markdown.startsWith("---\n");
}

async function removeStaleGeneratedFiles(skills) {
  const skillNames = new Set(skills.map((skill) => skill.name));

  await removeStaleSkillDirectories(
    path.join(rootDir, ".claude", "skills"),
    skillNames,
  );
  await removeStaleSkillDirectories(
    path.join(rootDir, ".codex", "skills"),
    skillNames,
  );
  await removeLegacyCodexFiles();
  await removeStaleFiles(
    path.join(rootDir, ".gemini", "commands", "repo"),
    (name) => name.endsWith(".toml") && !skillNames.has(name.slice(0, -5)),
  );
  await removeStaleGeminiExtension(skillNames);
}

async function removeStaleSkillDirectories(skillsDir, skillNames) {
  try {
    const entries = await readdir(skillsDir, { withFileTypes: true });

    await Promise.all(
      entries
        .filter((entry) => entry.isDirectory() && !skillNames.has(entry.name))
        .map((entry) =>
          rm(path.join(skillsDir, entry.name), {
            recursive: true,
            force: true,
          }),
        ),
    );
  } catch (error) {
    if (!isMissingPathError(error)) {
      throw error;
    }
  }
}

async function removeLegacyCodexFiles() {
  const codexSkillsDir = path.join(rootDir, ".codex", "skills");

  await removeStaleFiles(
    codexSkillsDir,
    (name) => name.endsWith(".md") && name !== "_index.md",
  );
}

async function removeStaleGeminiExtension(skillNames) {
  const extensionRoot = path.join(
    rootDir,
    ".gemini",
    "extensions",
    geminiExtensionName,
  );

  await removeStaleSkillDirectories(
    path.join(extensionRoot, "skills"),
    skillNames,
  );
  await removeStaleFiles(
    path.join(extensionRoot, "commands", "repo"),
    (name) => name.endsWith(".toml") && !skillNames.has(name.slice(0, -5)),
  );
}

async function removeStaleFiles(directoryPath, shouldRemove) {
  try {
    const entries = await readdir(directoryPath);

    await Promise.all(
      entries
        .filter(shouldRemove)
        .map((entry) => rm(path.join(directoryPath, entry), { force: true })),
    );
  } catch (error) {
    if (!isMissingPathError(error)) {
      throw error;
    }
  }
}

function isMissingPathError(error) {
  return Boolean(
    error &&
    typeof error === "object" &&
    "code" in error &&
    error.code === "ENOENT",
  );
}

async function writeAdapterReadmes(skills) {
  const claudeReadme = [
    "# Claude Adapter",
    "",
    generatedNotice,
    "",
    "This directory contains project-scoped Claude skills generated from the canonical skill sources in `ai/skills/`.",
    "",
    "- Project skills live in `.claude/skills/<skill-name>/SKILL.md`.",
    "- Shared project memory stays in the repository root `CLAUDE.md`.",
    "- Refresh these files with `pnpm ai:sync`.",
    "",
    "Available generated skills:",
    ...skills.map((skill) => `- \`${skill.name}\`: ${skill.useWhen}`),
    "",
  ].join("\n");

  const geminiReadme = [
    "# Gemini Adapter",
    "",
    generatedNotice,
    "",
    "This directory contains two official Gemini adapter forms generated from the canonical skill sources in `ai/skills/`.",
    "",
    "- Direct project commands live in `.gemini/commands/repo/*.toml` and can be invoked as `/repo:<skill-name>`.",
    `- Installable extension skills live in \`.gemini/extensions/${geminiExtensionName}/skills/<skill-name>/SKILL.md\`.`,
    `- To register the bundled extension, run \`gemini extensions link .gemini/extensions/${geminiExtensionName}\` from the repository root.`,
    "- Shared project memory stays in the repository root `GEMINI.md`.",
    "- Refresh these files with `pnpm ai:sync`.",
    "",
    "Available generated skills:",
    ...skills.map((skill) => `- \`${skill.name}\`: ${skill.useWhen}`),
    "",
  ].join("\n");

  const codexReadme = [
    "# Codex Adapter",
    "",
    generatedNotice,
    "",
    "This directory contains repository-scoped Codex skills generated from the canonical skill sources in `ai/skills/`.",
    "",
    "- Skills live in `.codex/skills/<skill-name>/SKILL.md`.",
    "- The repository entrypoint is still the root `AGENTS.md`.",
    "- Some Codex setups load skills from `$CODEX_HOME/skills`; if needed, symlink or copy `.codex/skills/*` there.",
    "- Refresh these files with `pnpm ai:sync`.",
    "",
  ].join("\n");

  const cursorReadme = [
    "# Cursor Adapter",
    "",
    generatedNotice,
    "",
    "This directory contains project rules generated from the canonical context in `ai/` and the repository entry in `AGENTS.md`.",
    "",
    "- Rules live in `.cursor/rules/*.mdc`.",
    "- Refresh these files with `pnpm ai:sync` after changing canonical AI context.",
    "- The root `AGENTS.md` remains the canonical repo entrypoint.",
    "",
  ].join("\n");

  await mkdir(path.join(rootDir, ".claude", "skills"), { recursive: true });
  await mkdir(path.join(rootDir, ".gemini", "commands", "repo"), {
    recursive: true,
  });
  await mkdir(path.join(rootDir, ".codex", "skills"), { recursive: true });
  await mkdir(path.join(rootDir, ".cursor", "rules"), { recursive: true });
  await mkdir(path.join(rootDir, ".github"), { recursive: true });

  await writeFile(path.join(rootDir, ".claude", "README.md"), claudeReadme);
  await writeFile(path.join(rootDir, ".gemini", "README.md"), geminiReadme);
  await writeFile(path.join(rootDir, ".codex", "README.md"), codexReadme);
  await writeFile(path.join(rootDir, ".cursor", "README.md"), cursorReadme);
}

async function writeGeminiExtensionFiles(skills) {
  const extensionRoot = path.join(
    rootDir,
    ".gemini",
    "extensions",
    geminiExtensionName,
  );
  const manifest = {
    name: geminiExtensionName,
    version: "0.1.0",
    description: `Repository AI skills for ${repoName}`,
    contextFileName: "GEMINI.md",
  };
  const extensionContext = [
    "# Gemini Extension Context",
    "",
    generatedNotice,
    "",
    `This extension bundles the repository skills defined in \`ai/skills/\` for \`${repoName}\`.`,
    "",
    "Bundled skills:",
    ...skills.map((skill) => `- \`${skill.name}\`: ${skill.useWhen}`),
    "",
    "Use the repository root `GEMINI.md` together with these skills when working inside this repo.",
    "",
  ].join("\n");

  await mkdir(path.join(extensionRoot, "skills"), { recursive: true });
  await mkdir(path.join(extensionRoot, "commands", "repo"), {
    recursive: true,
  });

  await writeFile(
    path.join(extensionRoot, "gemini-extension.json"),
    `${JSON.stringify(manifest, null, 2)}\n`,
  );
  await writeFile(path.join(extensionRoot, "GEMINI.md"), extensionContext);
}

async function writeClaudeSkill(skill, skillBody) {
  const skillDir = path.join(rootDir, ".claude", "skills", skill.name);

  await mkdir(skillDir, { recursive: true });
  await writeFile(path.join(skillDir, "SKILL.md"), skillBody);
}

async function writeGeminiCommand(skill) {
  const description = tomlBasicString(
    `Applies the repository's ${skill.name} workflow. Use when ${skill.useWhen}`,
  );
  const prompt = [
    "Use the repository workflow below as the authoritative guide for this task.",
    "",
    `@{${skill.sourcePath}}`,
    "",
    "Instructions:",
    "- Apply the workflow to the current conversation and workspace.",
    "- If the workflow asks you to load other canonical documents, load them before acting.",
    "- If command arguments are provided, treat them as the immediate task input.",
    "",
    "Task input:",
    "{{args}}",
  ].join("\n");
  const contents = [
    `description = ${description}`,
    "prompt = '''",
    prompt,
    "'''",
    "",
  ].join("\n");

  await writeFile(
    path.join(rootDir, ".gemini", "commands", "repo", `${skill.name}.toml`),
    contents,
  );
  await writeFile(
    path.join(
      rootDir,
      ".gemini",
      "extensions",
      geminiExtensionName,
      "commands",
      "repo",
      `${skill.name}.toml`,
    ),
    contents,
  );
}

async function writeGeminiExtensionSkill(skill, skillBody) {
  const skillDir = path.join(
    rootDir,
    ".gemini",
    "extensions",
    geminiExtensionName,
    "skills",
    skill.name,
  );

  await mkdir(skillDir, { recursive: true });
  await writeFile(path.join(skillDir, "SKILL.md"), skillBody);
}

async function writeCodexSkill(skill, skillBody) {
  const skillDir = path.join(rootDir, ".codex", "skills", skill.name);

  await mkdir(skillDir, { recursive: true });
  await writeFile(path.join(skillDir, "SKILL.md"), skillBody);
}

async function writeCodexIndex(skills) {
  const contents = [
    "# Codex Skill Index",
    "",
    generatedNotice,
    "",
    "Available generated skills:",
    ...skills.map(
      (skill) =>
        `- [${skill.name}](./${skill.name}/SKILL.md): ${skill.useWhen} (source: \`${skill.sourcePath}\`)`,
    ),
    "",
  ].join("\n");

  await writeFile(
    path.join(rootDir, ".codex", "skills", "_index.md"),
    contents,
  );
}

async function writeCopilotInstructions() {
  const contents = [
    "# GitHub Copilot Instructions",
    "",
    generatedNotice,
    "",
    "This repository is a PMF experimentation boilerplate built for fast iteration without giving up structure or verification.",
    "",
    "Canonical sources to follow first:",
    "- `AGENTS.md`",
    "- `ai/context/project.md`",
    "- `ai/context/engineering.md`",
    "- `ai/context/engineering-common.md`",
    "- `ai/context/spec-driven.md`",
    "- `ai/context/doc-sync.md`",
    "- `docs/agent-context.md`",
    "",
    "Working rules:",
    "- Keep `apps/web/src/app` thin. Put domain behavior in `apps/web/src/modules/*`.",
    "- Promote reuse only in this order: `module -> shared -> package`.",
    "- Validate inputs at the boundary. Keep model/use case files focused on orchestration.",
    "- For important multi-file work, create or update `docs/work-items/<work-id>/` before implementation.",
    "- When structure or workflow rules change, update the canonical Markdown docs in the same change.",
    "- Keep external provider failures from breaking the core user flow unless the provider is the product itself.",
    "",
    "Fast loops:",
    '- Use `pnpm work:new <slug> --request "..."` to create a work item scaffold.',
    "- Use `pnpm prd:new <slug>` to scaffold a canonical PRD in `docs/prds/`.",
    "- Use `pnpm feature:new --prd <slug> [--feature <feature-slug>]` to turn a PRD into a single feature work item plan.",
    "- Use `pnpm verify` for the default quality gate.",
    "- Use `pnpm verify:full` before handoff when user-facing flows or integrations changed.",
    "- Use `pnpm ai:sync` after changing `ai/`, `AGENTS.md`, or other adapter-driving docs.",
    "",
    "File-specific loading hints:",
    "- Frontend work: load `ai/context/engineering-frontend.md`.",
    "- Backend, schema, repository, or integration work: load `ai/context/engineering-backend.md`.",
    "- Docs or workflow changes: load `ai/context/doc-sync.md` and `docs/agent-context.md`.",
    "",
  ].join("\n");

  await writeFile(
    path.join(rootDir, ".github", "copilot-instructions.md"),
    contents,
  );
}

async function writeCursorRules() {
  const rules = [
    {
      fileName: "01-repo.mdc",
      description: "Repository-wide operating rules for PMF Boilerplate",
      alwaysApply: true,
      body: [
        "# PMF Boilerplate Repo Rule",
        "",
        "- Read `AGENTS.md`, `ai/context/project.md`, `ai/context/engineering.md`, `ai/context/engineering-common.md`, `ai/context/spec-driven.md`, and `ai/context/doc-sync.md` before substantial work.",
        "- Keep `apps/web/src/app` thin. Put product logic in `apps/web/src/modules/*`.",
        "- Promote shared code only in this order: `module -> shared -> package`.",
        "- For important multi-file work, create or update `docs/work-items/<work-id>/` before coding.",
        "- If a canonical PRD exists, prefer `pnpm feature:new --prd <slug>` before implementation so the feature work item docs stay normalized.",
        "- Run `pnpm verify` before handoff. Run `pnpm verify:full` when user-facing flows or integrations changed.",
        "- Refresh generated adapters with `pnpm ai:sync` after changing canonical AI context or adapter-entry docs.",
      ],
    },
    {
      fileName: "20-frontend.mdc",
      description: "Frontend rules for Next.js routes, modules, and shared UI",
      globs: ["apps/web/src/**/*.ts", "apps/web/src/**/*.tsx"],
      body: [
        "# Frontend Rule",
        "",
        "- Load `ai/context/engineering-frontend.md` for frontend work.",
        "- Keep `page.tsx`, `layout.tsx`, and `route.ts` files thin. Business logic belongs in modules, not route entry files.",
        "- Prefer module-local code first. Move code to `shared` or `packages` only after reuse is proven.",
        "- Keep forms resilient: visible error states, pending cleanup, and non-blocking optional providers.",
        "- Preserve the existing visual language unless the task explicitly asks for a redesign.",
      ],
    },
    {
      fileName: "30-backend.mdc",
      description:
        "Backend rules for schemas, repositories, actions, and integrations",
      globs: [
        "packages/db/src/**/*.ts",
        "packages/core/src/**/*.ts",
        "apps/web/src/modules/**/*.ts",
        "apps/web/src/app/api/**/*.ts",
      ],
      body: [
        "# Backend Rule",
        "",
        "- Load `ai/context/engineering-backend.md` for backend, schema, repository, or integration changes.",
        "- Validate at the boundary. Model and use-case files should orchestrate validated input rather than parse `unknown` directly.",
        "- Keep repository changes atomic where the product signal depends on multiple writes.",
        "- External integrations should fail loudly for operator visibility, but optional adapters should not corrupt the core flow.",
        "- Update analytics, error logging, and tests in the same change when persistence behavior changes.",
      ],
    },
    {
      fileName: "40-docs.mdc",
      description: "Documentation and workflow sync rules",
      globs: [
        "docs/**/*.md",
        "ai/**/*.md",
        "AGENTS.md",
        "CLAUDE.md",
        "GEMINI.md",
        "README.md",
        "scripts/**/*.mjs",
      ],
      body: [
        "# Docs Sync Rule",
        "",
        "- Treat repo Markdown as the source of truth for important work.",
        "- Load `ai/context/doc-sync.md` and `docs/agent-context.md` when changing docs, workflows, or adapters.",
        "- Update canonical docs first, then regenerate adapter outputs with `pnpm ai:sync`.",
        "- Do not duplicate full policy text across adapters. Keep adapters short and point them back to canonical docs.",
        "- If you change workflow commands or templates, update `README.md` and `docs/work-items/README.md` in the same change.",
      ],
    },
  ];

  for (const rule of rules) {
    await writeFile(
      path.join(rootDir, ".cursor", "rules", rule.fileName),
      buildCursorRule(rule),
    );
  }
}

function buildCursorRule(rule) {
  const frontmatter = [
    "---",
    `description: ${rule.description}`,
    ...(rule.globs ? [`globs: ${JSON.stringify(rule.globs)}`] : []),
    `alwaysApply: ${rule.alwaysApply ?? false}`,
    "---",
    "",
  ];

  return [...frontmatter, ...rule.body, ""].join("\n");
}

function yamlQuote(value) {
  return JSON.stringify(value);
}

function tomlBasicString(value) {
  return JSON.stringify(value);
}

main().catch((error) => {
  process.stderr.write(
    `${error instanceof Error ? error.message : String(error)}\n`,
  );
  process.exitCode = 1;
});
